import { Link, useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";

export default function Navbar() {
  const navigate = useNavigate();

  const [isLogged, setIsLogged] = useState(false);
  const [role, setRole] = useState(null);

  useEffect(() => {
    const token = localStorage.getItem("token");
    const userRole = localStorage.getItem("role");

    setIsLogged(!!token);
    setRole(userRole);
  }, []);

  const logout = () => {
    localStorage.clear();
    setIsLogged(false);
    setRole(null);
    navigate("/login");
  };

  return (
    <nav style={styles.nav}>
      {/* Left Side */}
      <div>
        <Link to="/" style={styles.link}>Home</Link>

        {isLogged && (role === "staff" || role === "admin") && (
          <>
            <Link to="/vehicles" style={styles.link}>Vehicles</Link>
            <Link to="/leads" style={styles.link}>Leads</Link>
            <Link to="/appointments" style={styles.link}>Manage Appointments</Link>
          </>
        )}

        {isLogged && role === "user" && (
          <>
            <Link to="/my-appointments" style={styles.link}>
              My Appointments
            </Link>
          </>
        )}
      </div>

      {/* Right Side */}
      <div>
        {isLogged ? (
          <>
            <span style={{ marginRight: 15 }}>
              {role?.toUpperCase()}
            </span>
            <button onClick={logout} style={styles.button}>
              Logout
            </button>
          </>
        ) : (
          <>
            <Link to="/login" style={styles.link}>Login</Link>
            <Link to="/register" style={styles.link}>Register</Link>
          </>
        )}
      </div>
    </nav>
  );
}

const styles = {
  nav: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: "12px 30px",
    background: "#111",
    color: "#fff"
  },
  link: {
    color: "#fff",
    marginRight: 20,
    textDecoration: "none",
    fontWeight: 500
  },
  button: {
    padding: "6px 12px",
    cursor: "pointer",
    background: "#ff4d4d",
    border: "none",
    color: "#fff",
    borderRadius: 4
  }
};
